server.ts:
```
import { delay } from "https://deno.land/std@0.136.0/async/mod.ts";

const worker = new Worker(new URL("./worker.ts", import.meta.url).href, {type: "module", deno: {permissions: "inherit",}, });

// First await: waits for a second, then continues running the module.
await delay(1000);

// Start listening on port 8080 of localhost.
const server = Deno.listen({ port: 8080 });
console.log(`HTTP webserver running.  Access it at:  http://localhost:8080/`);

// Connections to the server will be yielded up as an async iterable.
for await (const conn of server) 
{
  // In order to not be blocking, we need to handle each connection individually
  // without awaiting the function
  worker.postMessage(conn);
}
```

worker.ts:
```
self.onmessage = async (conn: Deno.Conn) =>
{
  // This "upgrades" a network connection into an HTTP connection.
  const httpConn = Deno.serveHttp(conn);

  // Each request sent over the HTTP connection will be yielded as an async
  // iterator from the HTTP connection.
  for await (const requestEvent of httpConn) 
  {
    // The native HTTP server uses the web standard `Request` and `Response`
    // objects.
    const body = `Your user-agent is:\n\n${
      requestEvent.request.headers.get("user-agent") ?? "Unknown"
    }`;

    // The requestEvent's `.respondWith()` method is how we send the response
    // back to the client.
    requestEvent.respondWith(
      new Response(body, {
        status: 200,
      }),
    );
  }
}
```

