```ts
/**
 * Here be dragons.
 *
 * The use of Deno's internals is highly discouraged,
 * as they are subject to rapid change.
 */

// @ts-ignore: I know what I'm doing
if (Deno.internal === undefined) {
    throw new Error("'Deno.internal' is undefined");
}

// @ts-ignore: I know what I'm doing
if (Deno[Deno.internal] === undefined) {
    throw new Error("'Deno[Deno.internal]' is undefined");
}

// @ts-ignore: I know what I'm doing
const { core } = Deno[Deno.internal];

if ( core === undefined) {
    throw new Error("'Deno[Deno.internal].core' is undefined");
}

const { ops } = core;

if (ops === undefined) {
    throw new Error("'Deno[Deno.internal].core.ops' is undefined");
}

const { op_ws_send_ping } = ops;

if (op_ws_send_ping === undefined) {
    throw new Error("'Deno[Deno.internal].core.ops.op_ws_send_ping' is undefined");
}

if (typeof op_ws_send_ping !== "function") {
    throw new Error("'Deno[Deno.internal].core.ops.op_ws_send_ping' is not a function");
}

const cache = new WeakMap<WebSocket, number>();

export const extactRid = (socket: WebSocket) => {
    const cached = cache.get(socket);

    if (cached !== undefined) {
        return cached;
    }

    const symbols = Object.getOwnPropertySymbols(socket);
    const symbol = symbols.find(symbol => symbol.description === "[[rid]]");

    if (symbol === undefined) {
        throw new Error("Unable to extract socket's RID");
    }

    // @ts-ignore: I know what I'm doing
    const rid = socket[symbol];

    if (typeof rid !== "number") {
        throw new Error("Socket's RID is not a number");
    }

    cache.set(socket, rid);

    return rid;
};

export const ping = (socket: WebSocket) => {
    try {
        op_ws_send_ping(extactRid(socket));
    }
    catch(e) {
        console.error("Error sending ping:");
        console.error(e);
    }
};
```

