```ts
const esbuild = require('esbuild');

async function buildFromStdin() {
  const result = await esbuild.build({
    bundle: true,
    stdin: {
      contents: `import { someFunction } from './utils'; console.log(someFunction());`,
      resolveDir: __dirname, // Resolve modules relative to the current directory
      sourcefile: 'input.js', // Optional: Name for the input in sourcemaps
      loader: 'ts', // Optional: Specify the loader for the input
    },
    outfile: 'output.js',
  });
  console.log(result);
}

buildFromStdin();
